sql:
SELECT subsector_name, data_collection_frequency
FROM subsectors
WHERE data_collection_frequency = 'quarterly';

external_knowledge:
- "Last 6 months" refers to the time period from 6 months before the current date to the current date; 
- "Accessed" means a user has opened or used the dataset; 
- "Top 3 most accessed datasets" means the 3 datasets with the highest number of accesses.

sql:
SELECT COUNT(dataset_id)
FROM datasets
WHERE sector_id = (SELECT sector_id FROM sectors WHERE sector_name = 'Agriculture');
